    summary: { points: ["$42 ROI per $1 spent — highest of any marketing channel", "Segment your list — personalized emails perform 6x better", "Welcome sequences set the relationship tone", "A/B test subject lines — small changes = big impact"], quote: { text: "Email has an ability many channels don't: creating valuable, personal touches at scale.", author: "David Newman" } },
