    summary: { points: ["Promotions drive short-term sales; loyalty drives long-term value", "Starbucks Rewards: 3x more spend. Amazon Prime: 4.6x", "Balance promotions — too many train customers to wait for deals", "Loyalty programs should reward behavior, not just purchases"], quote: { text: "Customer loyalty is not won by being the cheapest. It's won by being the best.", author: "Marketing Principle" } },
